import{c as e,Q as a,j as r,m as s}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Customers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/customers.md","filePath":"guide/admin/customers.md","lastUpdated":1778862269000}'),n={name:"guide/admin/customers.md"};function o(i,t,l,d,u,c){return a(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="customers" tabindex="-1">Customers <a class="header-anchor" href="#customers" aria-label="Permalink to &quot;Customers&quot;">​</a></h1><p>The <strong>Customers</strong> page is the master list of every company you have a contract with. From here you onboard new customers, change their lifecycle status, and drill into their detail page to manage tenants, users, security, billing, and configuration.</p><h2 id="list-page" tabindex="-1">List page <a class="header-anchor" href="#list-page" aria-label="Permalink to &quot;List page&quot;">​</a></h2><h3 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h3><ul><li><strong>Search</strong> — matches customer name or billing contact email.</li><li><strong>Status</strong> — All / Active / Suspended / Churned.</li><li><strong>Plan</strong> — All / Starter / Professional / Enterprise (or any custom plans).</li><li><strong>Clear</strong> — appears when any filter is active.</li><li><strong>New Customer</strong> button (top right).</li><li>Count chip — &quot;N customers&quot; or &quot;N of X&quot; when filtered.</li></ul><h3 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Clickable link to the customer detail page.</td></tr><tr><td><strong>Plan</strong></td><td>Display name with version suffix. A warning icon appears if the customer is on a version older than the current.</td></tr><tr><td><strong>Billing Contact</strong></td><td>Email, or <code>—</code> if none.</td></tr><tr><td><strong>Status</strong></td><td>Active / Suspended / Churned badge.</td></tr><tr><td><strong>Created</strong></td><td>Relative timestamp.</td></tr><tr><td><strong>Actions</strong></td><td>Inline icon buttons — Suspend, Reactivate, Churn, Delete.</td></tr></tbody></table><h3 id="row-actions" tabindex="-1">Row actions <a class="header-anchor" href="#row-actions" aria-label="Permalink to &quot;Row actions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Suspend</strong> (power icon)</td><td>Opens a confirmation modal with a <strong>required reason</strong> field. Suspended customers&#39; users cannot sign in.</td></tr><tr><td><strong>Reactivate</strong> (rotate icon, suspended only)</td><td>Direct action — no modal.</td></tr><tr><td><strong>Churn</strong> (trash icon)</td><td>Opens a confirmation modal with a <strong>required reason</strong> field. Churn is the &quot;this customer is gone&quot; state.</td></tr><tr><td><strong>Delete</strong> (X icon)</td><td>Hard delete. <strong>Customers with active tenants cannot be deleted</strong> — archive the tenants first.</td></tr></tbody></table><h2 id="creating-a-new-customer" tabindex="-1">Creating a new customer <a class="header-anchor" href="#creating-a-new-customer" aria-label="Permalink to &quot;Creating a new customer&quot;">​</a></h2><p>Click <strong>New Customer</strong>. The modal asks for:</p><ul><li><strong>Name</strong> — display name of the company.</li><li><strong>Plan</strong> — pick from available plans.</li><li><strong>Billing Contact Email</strong> — invoices and billing-related notifications go here.</li><li><strong>Timezone</strong> — used for invoice period boundaries and report formatting.</li></ul><p>Click <strong>Create</strong>. The customer is created in <code>active</code> status with no tenants. You typically follow up with: create tenants, invite users, and confirm plan / billing settings.</p><h2 id="customer-detail-page" tabindex="-1">Customer detail page <a class="header-anchor" href="#customer-detail-page" aria-label="Permalink to &quot;Customer detail page&quot;">​</a></h2><p>Click a customer&#39;s name to open the detail page. The header shows the customer&#39;s name, status badge, and a <strong>Focus on this customer</strong> button (visible to operators with broad access — enters focus mode for this customer).</p><p>Below the header is a tab strip:</p><h3 id="overview-tab" tabindex="-1">Overview tab <a class="header-anchor" href="#overview-tab" aria-label="Permalink to &quot;Overview tab&quot;">​</a></h3><p>Two cards on this tab:</p><ul><li><strong>Customer Details</strong> — Plan, Plan version, Billing Contact, Timezone, IDP Org ID, Created date.</li><li><strong>Billing Summary</strong> — credit balance.</li></ul><h3 id="tenants-tab" tabindex="-1">Tenants tab <a class="header-anchor" href="#tenants-tab" aria-label="Permalink to &quot;Tenants tab&quot;">​</a></h3><p>A list of every tenant owned by this customer with columns Name, Instance, Status, Created. Row actions:</p><ul><li><strong>Suspend / Resume</strong> for active vs. suspended tenants.</li><li><strong>Archive</strong> (with required reason) for active or suspended tenants.</li><li><strong>Restore</strong> for archived tenants.</li></ul><p>For full tenant operations (move, migrate, edit licensing) use the <a href="./tenants">Tenants</a> page or open the tenant directly.</p><h3 id="users-tab" tabindex="-1">Users tab <a class="header-anchor" href="#users-tab" aria-label="Permalink to &quot;Users tab&quot;">​</a></h3><p>A server-paginated table of every user assigned to the customer. Expand a row to see the user&#39;s full profile and all tenant assignments.</p><p><strong>Columns:</strong> Name, Email, Portal Role, Status, Tenants count, Instances count, Identity type (Internal / External), MFA enabled.</p><p><strong>Filters:</strong> Status, Portal Role, Assignment state, Identity type, MFA. Any custom user attributes the customer has enabled appear as additional filters.</p><p><strong>Actions:</strong></p><ul><li><strong>Invite Users</strong> (top right) — bulk invite. Paste emails or upload an Excel file. The modal shows a review step where you set a portal role per invitee and flags collisions: <ul><li>Users already in this customer — skipped.</li><li>Users existing in the system but not in this customer — granted access.</li></ul></li><li><strong>Assign tenant</strong> (user + icon, per row) — opens a modal: pick Instance → Tenant → Role.</li><li><strong>Suspend / Reactivate</strong> (per row).</li><li><strong>Resend Invite</strong> or <strong>Transfer Ownership</strong> (ellipsis menu, available for invited or external users).</li></ul><p>The expanded row shows Invited At, Last Login, Profile Completed flag, IDP User ID, all custom attributes, and a mini-table of the user&#39;s tenant assignments.</p><h3 id="security-tab" tabindex="-1">Security tab <a class="header-anchor" href="#security-tab" aria-label="Permalink to &quot;Security tab&quot;">​</a></h3><p>Authentication, API keys, OAuth clients, IP allow-lists, and other customer-level security configuration.</p><h3 id="service-accounts-tab" tabindex="-1">Service Accounts tab <a class="header-anchor" href="#service-accounts-tab" aria-label="Permalink to &quot;Service Accounts tab&quot;">​</a></h3><p>Machine credentials for the customer. Create, view, revoke. The secret is shown once at creation — copy it then.</p><h3 id="webhooks-tab" tabindex="-1">Webhooks tab <a class="header-anchor" href="#webhooks-tab" aria-label="Permalink to &quot;Webhooks tab&quot;">​</a></h3><p>Outbound HTTP endpoints subscribed to platform events. Configure URL, event types, auth headers. Includes delivery history with retries.</p><h3 id="user-attributes-tab" tabindex="-1">User Attributes tab <a class="header-anchor" href="#user-attributes-tab" aria-label="Permalink to &quot;User Attributes tab&quot;">​</a></h3><p>The customer-level configuration for which user attributes are enabled, their order, and per-attribute defaults. See <a href="./user-attributes">User Attributes</a> for the platform-wide attribute definitions.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Plans are tied to versions — see <a href="./../concepts/plans-and-meters">Plans &amp; Meters</a>. If a customer is on an old plan version, a warning icon appears on the list page, and an <strong>Upgrade to v[N]</strong> banner appears on their billing page.</li><li>Suspending a customer is a heavy hammer. To pause only one tenant, suspend the tenant from the <a href="./tenants">Tenants</a> page.</li><li>Empty filtered state shows &quot;No customers match your filters&quot;. Empty unfiltered state shows a generic empty message and the <strong>New Customer</strong> button is the only way forward.</li></ul>',40)])])}const m=e(n,[["render",o]]);export{g as __pageData,m as default};
